+fn parse_function_key_token(s: &str) -> Option<u8> {
+    let rest = s.strip_prefix('F').or_else(|| s.strip_prefix('f'))?;
+    if rest.is_empty() || !rest.chars().all(|ch| ch.is_ascii_digit()) {
+        return None;
+    }
+    rest.parse().ok()
+}
