+fn parse_key_event_kind(phase: &str, repeat: bool) -> KeyEventKind {
+    if phase.eq_ignore_ascii_case("up") || phase.eq_ignore_ascii_case("release") {
+        KeyEventKind::Release
+    } else if repeat {
+        KeyEventKind::Repeat
+    } else {
+        KeyEventKind::Press
+    }
+}
